\displaystyle{\begin{aligned}[t]
    \frac{7}{16} \div \left(-\frac{5}{12}\right)
        \amp = \frac{7}{16} \cdot \left(-\frac{12}{5}\right) \amp \hbox{We can divide the first denominator and the second numerator by 4.}\\
        \amp = \frac{7}{4 }\cdot\left(-\frac{3}{5}\right) \\
        \amp = -\frac{21}{20}
\end{aligned}
    }
